external_knowledge:
- "Higher than usual" is defined as being above the average closing price of all entries in the market data; 
- "Time stamps" refer to the datetime stamp for the data point;
- "Market risk factors" are the Mkt-RF values associated with each data point.

sql:
SELECT datetime, mkt_rf
FROM market_data
WHERE close_price > (SELECT AVG(close_price) FROM market_data);

SELECT AVG(mkt_rf) AS average_mkt_rf, SUM(volume) AS total_volume
FROM market_data
WHERE id <= 3;

SELECT id, datetime, AVG(close_price) AS average_close_price
FROM market_data
GROUP BY id, datetime;

SELECT department, COUNT(researcher_id) AS researcher_count
FROM researchers
GROUP BY department;
